class Solution:
    def countPairs(self, nums, low, high):
        count = 0
        n = len(nums)
        for i in range(n):
            for j in range(i + 1, n):
                x = nums[i] ^ nums[j]
                if low <= x <= high:
                    count += 1
        return count

