class Solution:
    def countPairs(self, nums, low, high):
        BITS = 15
        # trie as dict-of-dicts with counts
        root = {}
        def insert(num):
            node = root
            for b in range(BITS, -1, -1):
                bit = (num >> b) & 1
                if bit not in node:
                    node[bit] = {'cnt': 0}
                node = node[bit]
                node['cnt'] += 1
        def count_less(num, limit):
            # number of inserted partners p with (num ^ p) < limit
            node = root
            total = 0
            for b in range(BITS, -1, -1):
                if node is None:
                    break
                nb = (num >> b) & 1
                lb = (limit >> b) & 1
                if lb == 1:
                    # partners whose xor bit here is 0 keep prefix below limit
                    same = node.get(nb)
                    if same is not None:
                        total += same['cnt']
                    node = node.get(1 - nb)
                else:
                    node = node.get(nb)
            return total
        ans = 0
        for num in nums:
            ans += count_less(num, high + 1) - count_less(num, low)
            insert(num)
        return ans

