var countPairs = function(nums, low, high) {
    const BITS = 15;
    const root = { cnt: 0, ch: [null, null] };
    const insert = (num) => {
        let node = root;
        for (let b = BITS; b >= 0; b--) {
            const bit = (num >> b) & 1;
            if (!node.ch[bit]) node.ch[bit] = { cnt: 0, ch: [null, null] };
            node = node.ch[bit];
            node.cnt++;
        }
    };
    const countLess = (num, limit) => {
        let node = root;
        let total = 0;
        for (let b = BITS; b >= 0; b--) {
            if (!node) break;
            const nb = (num >> b) & 1;
            const lb = (limit >> b) & 1;
            if (lb === 1) {
                const same = node.ch[nb];
                if (same) total += same.cnt;
                node = node.ch[1 - nb];
            } else {
                node = node.ch[nb];
            }
        }
        return total;
    };
    let ans = 0;
    for (const num of nums) {
        ans += countLess(num, high + 1) - countLess(num, low);
        insert(num);
    }
    return ans;
};
